const fs = require('fs');
const path = require('path');
const { chromium } = require('playwright');

(async () => {
  const report = {
    login_success: false,
    pages_visited: [],
    errors: [],
    summary: { total_pages: 0, total_errors: 0 }
  };
  const P21_URL = process.env.P21_URL;
  const USERNAME = process.env.P21_USERNAME;
  const PASSWORD = process.env.P21_PASSWORD;
  if (!P21_URL || !USERNAME || !PASSWORD) {
    report.errors.push('Missing required environment variables');
    console.error('Missing required environment variables');
    console.log(JSON.stringify(report, null, 2));
    process.exit(1);
  }
  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--ignore-certificate-errors']
  });
  const context = await browser.newContext();
  const page = await context.newPage();
  try {
    await page.goto(P21_URL, { waitUntil: 'networkidle' });
    // Try to locate input fields by common selectors
    const usernameSelector = 'input[name*="user" i], input[id*="user" i], input[type="email" i], input[type="text" i]';
    const passwordSelector = 'input[name*="pass" i], input[id*="pass" i], input[type="password" i]';
    await page.waitForSelector(usernameSelector, { timeout: 5000 });
    await page.fill(usernameSelector, USERNAME);
    await page.fill(passwordSelector, PASSWORD);
    // Submit the form - try pressing Enter on password field
    await Promise.all([
      page.waitForNavigation({ waitUntil: 'networkidle' }),
      page.press(passwordSelector, 'Enter')
    ]);
    // Screenshot after login
    const loginScreenshot = '/tmp/p21-login.png';
    await page.screenshot({ path: loginScreenshot, fullPage: true });
    const urlAfter = page.url();
    const titleAfter = await page.title();
    const loginSuccess = !/login/i.test(urlAfter) && !/login/i.test(titleAfter);
    report.login_success = loginSuccess;
    if (!loginSuccess) {
      report.errors.push('Login appears to have failed; URL or title still contains "login"');
    }
    // Function to sanitize label for filenames
    const sanitize = (s) => s.replace(/[^a-zA-Z0-9]/g, '_');
    // Collect top‑level navigation items
    const navLinks = await page.$$eval('nav a, .sidebar a, .menu a, [role="menuitem"], [role="tab"]', (anchors) => {
      return anchors.map(a => ({
        label: a.innerText.trim(),
        href: a.href
      })).filter(item => item.label && item.href);
    });
    // Deduplicate by href
    const uniqueLinks = [];
    const seen = new Set();
    for (const link of navLinks) {
      if (!seen.has(link.href)) {
        seen.add(link.href);
        uniqueLinks.push(link);
      }
    }
    for (const link of uniqueLinks) {
      try {
        const label = link.label || link.href;
        const sanitized = sanitize(label);
        // Open link, handling possible new page
        const [newPage] = await Promise.all([
          context.waitForEvent('page', { timeout: 2000 }).catch(() => null),
          page.evaluate((href) => { window.open(href, '_blank'); }, link.href)
        ]);
        const targetPage = newPage || page;
        await targetPage.waitForLoadState('networkidle', { timeout: 15000 }).catch(() => {});
        const screenshotPath = `/tmp/p21-${sanitized}.png`;
        await targetPage.screenshot({ path: screenshotPath, fullPage: true });
        const currentUrl = targetPage.url();
        const pageTitle = await targetPage.title();
        // Sub‑menu items
        const subItems = await targetPage.$$eval('a, button', (els) => {
          return els.map(el => el.innerText.trim()).filter(txt => txt);
        });
        report.pages_visited.push({
          label,
          url: currentUrl,
          title: pageTitle,
          sub_items: subItems,
          screenshot: screenshotPath
        });
        // If we opened a new tab, close it and go back to original page
        if (newPage) {
          await newPage.close();
        }
      } catch (e) {
        report.errors.push(`Error processing nav item "${link.label}": ${e.message}`);
      }
    }
  } catch (e) {
    report.errors.push(`Fatal error: ${e.message}`);
  } finally {
    await browser.close();
    report.summary.total_pages = report.pages_visited.length;
    report.summary.total_errors = report.errors.length;
    const reportPath = '/tmp/p21-report.json';
    fs.writeFileSync(reportPath, JSON.stringify(report, null, 2), 'utf-8');
    console.log(JSON.stringify(report, null, 2));
  }
})();

